module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);
    reg [1:0] i_state = ZERO;
    reg [1:0] i_next_state = ZERO;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            i_state <= ZERO;
        else
            i_state <= i_next_state;
    end
    always @(*) begin
        case (i_state)
            ZERO:
                if (a == 0) begin
                    i_next_state <= ZERO;
                    rise <= 0;
                    down <= 0;
                end else begin
                    i_next_state <= ONE;
                    rise <= 1;
                    down <= 0;
                end
            ONE:
                if (a == 1) begin
                    i_next_state <= ONE;
                    rise <= 0;
                    down <= 0;
                end else begin
                    i_next_state <= ZERO;
                    rise <= 0;
                    down <= 1;
                end
        endcase
    end
endmodule
